                // Vertical line, slope is infinity, use x-intercept
                key = `inf,${x1}`;
            } else {
                const slope = (y2 - y1) / (x2 - x1);
                const intercept = y1 - slope * x1;
                key = `${slope},${intercept}`;
            }
            if (!lines.has(key)) {
                lines.set(key, new Set());
            }
            lines.get(key).add(i);
            lines.get(key).add(j);
        }
    }

    const processedPairs = new Set();

    // Iterate through all pairs of parallel lines
    for (const [key1, set1] of lines) {
        for (const [key2, set2] of lines) {
            if (key1 === key2) continue;
            const pairKey = [key1, key2].sort().join('|');
            if (processedPairs.has(pairKey)) continue;
            processedPairs.add(pairKey);

            // Check if the lines are parallel (same slope)
            const slope1 = key1.split(',')[0];
            const slope2 = key2.split(',')[0];
            if (slope1 !== slope2) continue;

            // Find the intersection of the two sets (points on both lines)
            const commonPoints = new Set();
            for (const point of set1) {
                if (set2.has(point)) {
                    commonPoints.add(point);
                }
            }

            // The number of points unique to each line
            const unique1 = set1.size - commonPoints.size;
            const unique2 = set2.size - commonPoints.size;

            // The number of ways to choose 2 points from each line, avoiding common points
            if (unique1 >= 2 && unique2 >= 2) {
                const ways = (unique1 * (unique1 - 1) / 2) * (unique2 * (unique2 - 1) / 2);
                count += ways;
            }
        }
    }

    return count;
}
